mapper.select:
SELECT COUNT(*)
FROM complex_member_attendance a
JOIN complex_classes c ON c.seq = a.class_seq
WHERE a.member_seq = #{memberSeq}
  AND c.branch_seq = #{branchSeq}

SELECT COUNT(*)
FROM complex_member_attendance a
JOIN complex_classes c ON c.seq = a.class_seq
WHERE a.member_seq = #{staffSeq}
  AND c.branch_seq = #{branchSeq}
